import{_ as a,c as i,o as e,ak as r}from"./chunks/framework.CYxz2ou1.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"NanoGrid/A-小方格/2-需求规划.md","filePath":"NanoGrid/A-小方格/2-需求规划.md","lastUpdated":1775467143000}'),h={name:"NanoGrid/A-小方格/2-需求规划.md"};function o(t,l,n,u,d,s){return e(),i("div",null,[...l[0]||(l[0]=[r('<blockquote><p>当前状态：后端采用 Java/Spring Boot，前端采用 Flutter 已实现功能格子（29 个）：account, alarm, anniversary, big_wheel, bmi, bookshelf, calculator, calendar, canvas, card, clock, coin, dice, drink_plan, gomoku, handscrollingtext, housemoneycalc, life_grid, pomodoro, qrcode, random, rmbconvertor, snake, sudoku, todo, weather</p></blockquote><hr><h2 id="阶段一-基础架构完善-优先级最高" tabindex="-1">阶段一：基础架构完善（优先级最高） <a class="header-anchor" href="#阶段一-基础架构完善-优先级最高" aria-label="Permalink to &quot;阶段一：基础架构完善（优先级最高）&quot;">​</a></h2><p>这些功能是是后续所有功能的基础，必须先完成。</p><h3 id="_1-1-用户体系" tabindex="-1">1.1. 用户体系 <a class="header-anchor" href="#_1-1-用户体系" aria-label="Permalink to &quot;1.1. 用户体系&quot;">​</a></h3><p>当前只有注册页面，需要完善登录体系。</p><h4 id="登录功能" tabindex="-1">登录功能 <a class="header-anchor" href="#登录功能" aria-label="Permalink to &quot;登录功能&quot;">​</a></h4><ul><li>[ ] 注册功能</li><li>[ ] 邮箱登录</li><li>[ ] 手机号密码登录</li><li>[ ] 微信登录</li><li>[ ] QQ 登录</li><li>[ ] 关联账号绑定</li></ul><h4 id="账号管理" tabindex="-1">账号管理 <a class="header-anchor" href="#账号管理" aria-label="Permalink to &quot;账号管理&quot;">​</a></h4><ul><li>[ ] 找回密码（忘记密码时重置）</li><li>[ ] 修改密码（个人中心修改密码）</li><li>[ ] 退出登录</li><li>[ ] 头像上传（修改个人头像）</li><li>[ ] 个人资料编辑（昵称、性别、生日等）</li></ul><h3 id="_1-2-通用-ui-组件" tabindex="-1">1.2. 通用 UI 组件 <a class="header-anchor" href="#_1-2-通用-ui-组件" aria-label="Permalink to &quot;1.2. 通用 UI 组件&quot;">​</a></h3><p>开发可复用的基础组件，提高后续开发效率。</p><ul><li>[ ] 通用开关按钮组件</li><li>[ ] 通用确认/取消按钮样式</li><li>[ ] 通用弹窗通知样式</li><li>[ ] 图片选择组件</li><li>[ ] 图片分享功能（支持微信等渠道）</li></ul><p>Prompt：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>现在APP的底部有一个debug的TAB，其页面有一个页面1的按钮，给我开发一个新页面，点击页面1按钮跳转这个页面。我现在需要做一些通用的UI组件，需要给各种功能格子使用。主要有几种组件：1. 开关按钮样式 2. 确认、取消的弹出样式 3. 弹出通知样式。帮我设计与实现一些常见的这些组件样式的demo，放到这个新的页面上，我需要挑选。风格是扁平淡色风格即可。你也可以再考虑有没有什么别的通用的组件。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_1-3-核心服务能力" tabindex="-1">1.3. 核心服务能力 <a class="header-anchor" href="#_1-3-核心服务能力" aria-label="Permalink to &quot;1.3. 核心服务能力&quot;">​</a></h3><h4 id="日志相关" tabindex="-1">日志相关 <a class="header-anchor" href="#日志相关" aria-label="Permalink to &quot;日志相关&quot;">​</a></h4><ul><li>[ ] 日志与埋点功能（日志打印、记录、上报）<strong>问题的排查！debug 很重要</strong>。</li><li>[ ] 网络请求日志都要打日志</li></ul><h4 id="资源预加载" tabindex="-1">资源预加载 <a class="header-anchor" href="#资源预加载" aria-label="Permalink to &quot;资源预加载&quot;">​</a></h4><ul><li>[ ] 资源预拉取与缓存机制（OSS 资源缓存、缓存管理）</li></ul><h4 id="功能插件化" tabindex="-1">功能插件化 <a class="header-anchor" href="#功能插件化" aria-label="Permalink to &quot;功能插件化&quot;">​</a></h4><ul><li>[ ] 功能的模块式加载（插件化、功能功能集市、可移除）</li></ul><hr><h2 id="阶段二-app-基础功能" tabindex="-1">阶段二：APP 基础功能 <a class="header-anchor" href="#阶段二-app-基础功能" aria-label="Permalink to &quot;阶段二：APP 基础功能&quot;">​</a></h2><p>每个 APP 必备的基础体验功能。</p><h3 id="_2-1-启动与引导" tabindex="-1">2.1. 启动与引导 <a class="header-anchor" href="#_2-1-启动与引导" aria-label="Permalink to &quot;2.1. 启动与引导&quot;">​</a></h3><ul><li>[ ] 启动页/Splash 页（品牌展示、广告位）</li><li>[ ] 引导页/首次使用教程（新手引导）</li><li>[ ] 版本更新检测（自动检查并提示更新）</li></ul><h3 id="_2-2-发现与推广" tabindex="-1">2.2. 发现与推广 <a class="header-anchor" href="#_2-2-发现与推广" aria-label="Permalink to &quot;2.2. 发现与推广&quot;">​</a></h3><ul><li>[ ] 分享 APP（邀请朋友使用）</li><li>[ ] 应用评分（引导去应用商店评分）</li></ul><h3 id="_2-3-首页增强" tabindex="-1">2.3. 首页增强 <a class="header-anchor" href="#_2-3-首页增强" aria-label="Permalink to &quot;2.3. 首页增强&quot;">​</a></h3><ul><li>[ ] 首页支持大卡片展示</li><li>[ ] 首页功能支持拖拽排序</li><li>[ ] 首页功能分类展示</li><li>[ ] 功能支持收藏/置顶</li><li>[ ] 功能搜索（快速找到功能格子）</li><li>[ ] 多种字体支持</li></ul><h3 id="_2-4-通知与提示" tabindex="-1">2.4. 通知与提示 <a class="header-anchor" href="#_2-4-通知与提示" aria-label="Permalink to &quot;2.4. 通知与提示&quot;">​</a></h3><ul><li>[ ] 下拉横幅通知（用户可独立设置）</li><li>[ ] 系统震动提示</li><li>[ ] 音乐提示（内置部分音效资源）</li></ul><h3 id="_2-5-功能卡片打通" tabindex="-1">2.5. 功能卡片打通 <a class="header-anchor" href="#_2-5-功能卡片打通" aria-label="Permalink to &quot;2.5. 功能卡片打通&quot;">​</a></h3><ul><li>[ ] 天气功能在首页展示当前地区天气</li><li>[ ] 番茄钟在首页展示倒计时</li><li>[ ] 其他功能的状态卡片展示</li></ul><hr><h2 id="阶段三-设置与个性化" tabindex="-1">阶段三：设置与个性化 <a class="header-anchor" href="#阶段三-设置与个性化" aria-label="Permalink to &quot;阶段三：设置与个性化&quot;">​</a></h2><h3 id="_3-1-主题与显示" tabindex="-1">3.1. 主题与显示 <a class="header-anchor" href="#_3-1-主题与显示" aria-label="Permalink to &quot;3.1. 主题与显示&quot;">​</a></h3><ul><li>[ ] 深色模式（日间/夜间主题切换）</li><li>[ ] 支持切换主题配色</li><li>[ ] 支持不同风格皮肤</li><li>[ ] 语言切换（中英文切换入口）</li><li>[ ] 字体大小调节（适老化功能）</li></ul><h3 id="_3-2-通知与隐私设置" tabindex="-1">3.2. 通知与隐私设置 <a class="header-anchor" href="#_3-2-通知与隐私设置" aria-label="Permalink to &quot;3.2. 通知与隐私设置&quot;">​</a></h3><ul><li>[ ] 通知设置（各功能开关通知权限）</li><li>[ ] 隐私设置（数据使用偏好）</li><li>[ ] 清除缓存（清理本地缓存）</li></ul><hr><h2 id="阶段四-现有功能增强与修复" tabindex="-1">阶段四：现有功能增强与修复 <a class="header-anchor" href="#阶段四-现有功能增强与修复" aria-label="Permalink to &quot;阶段四：现有功能增强与修复&quot;">​</a></h2><p>打磨已有 29 个功能格子，提升用户体验。</p><h3 id="_4-1-简单功能格子增强" tabindex="-1">4.1. 简单功能格子增强 <a class="header-anchor" href="#_4-1-简单功能格子增强" aria-label="Permalink to &quot;4.1. 简单功能格子增强&quot;">​</a></h3><ul><li>[ ] 投硬币：增加统计功能、自定义正反面</li><li>[ ] 骰子：支持多骰子、自定义面数</li><li>[ ] 随机数：范围记忆、常用值快捷</li><li>[ ] 翻扑克牌：多种牌面、发牌动画</li><li>[ ] 二维码生成器：批量生成、扫描识别</li></ul><h3 id="_4-2-复杂功能增强" tabindex="-1">4.2. 复杂功能增强 <a class="header-anchor" href="#_4-2-复杂功能增强" aria-label="Permalink to &quot;4.2. 复杂功能增强&quot;">​</a></h3><ul><li>[ ] 待办清单：支持子任务、标签、提醒</li><li>[ ] 科学计算器：计算历史、自定义常数</li><li>[ ] 账本：图表可视化、预算提醒</li><li>[ ] 番茄钟：统计报表、白名单应用</li><li>[ ] 贪吃蛇：排行榜、多种难度</li><li>[ ] 数独：难度选择、提示功能</li><li>[ ] 画板：图层、撤销重做、贴纸</li></ul><h3 id="_4-3-数据相关功能" tabindex="-1">4.3. 数据相关功能 <a class="header-anchor" href="#_4-3-数据相关功能" aria-label="Permalink to &quot;4.3. 数据相关功能&quot;">​</a></h3><ul><li>[ ] 日历：支持农历、节日标注</li><li>[ ] 天气：多城市管理、预警通知</li><li>[ ] 闹钟：贪睡模式、渐强铃声</li><li>[ ] 纪念日：倒计时提醒、每年重复</li><li>[ ] 足迹地图：旅行记录统计</li></ul><hr><h2 id="阶段五-新增功能格子-由简入繁" tabindex="-1">阶段五：新增功能格子（由简入繁） <a class="header-anchor" href="#阶段五-新增功能格子-由简入繁" aria-label="Permalink to &quot;阶段五：新增功能格子（由简入繁）&quot;">​</a></h2><h3 id="_5-1-简单工具-1-2-天" tabindex="-1">5.1. 简单工具（1-2 天） <a class="header-anchor" href="#_5-1-简单工具-1-2-天" aria-label="Permalink to &quot;5.1. 简单工具（1-2 天）&quot;">​</a></h3><ul><li>[ ] 人民币大写转换</li><li>[ ] BMI 计算器（已有，需检查）</li><li>[ ] 房贷计算器</li><li>[ ] 闪屏时钟/全屏时钟（已有 clock，需检查）</li><li>[ ] 手持弹幕</li></ul><h3 id="_5-2-中等复杂工具-3-5-天" tabindex="-1">5.2. 中等复杂工具（3-5 天） <a class="header-anchor" href="#_5-2-中等复杂工具-3-5-天" aria-label="Permalink to &quot;5.2. 中等复杂工具（3-5 天）&quot;">​</a></h3><ul><li>[ ] 五子棋（已有 gomoku，需检查）</li><li>[ ] 扫雷</li><li>[ ] 奶茶计划（已有 drink_plan，需检查）</li><li>[ ] 大转盘（已有 big_wheel，需检查）</li><li>[ ] 有意义的一天</li></ul><h3 id="_5-3-复杂工具-1-周" tabindex="-1">5.3. 复杂工具（1 周+） <a class="header-anchor" href="#_5-3-复杂工具-1-周" aria-label="Permalink to &quot;5.3. 复杂工具（1 周+）&quot;">​</a></h3><ul><li>[ ] 人生格子（已有 life_grid，需检查）</li><li>[ ] 书架（已有 bookshelf，需检查）</li><li>[ ] 背单词</li><li>[ ] 记忆卡片</li><li>[ ] 买菜搭子</li></ul><hr><h2 id="阶段六-数据与云端" tabindex="-1">阶段六：数据与云端 <a class="header-anchor" href="#阶段六-数据与云端" aria-label="Permalink to &quot;阶段六：数据与云端&quot;">​</a></h2><h3 id="_6-1-数据管理" tabindex="-1">6.1. 数据管理 <a class="header-anchor" href="#_6-1-数据管理" aria-label="Permalink to &quot;6.1. 数据管理&quot;">​</a></h3><ul><li>[ ] 云端同步（用户数据跨设备同步）</li><li>[ ] 数据备份与恢复（导出/导入数据）</li><li>[ ] 使用统计（各功能使用时长统计）</li></ul><h3 id="_6-2-帮助与反馈" tabindex="-1">6.2. 帮助与反馈 <a class="header-anchor" href="#_6-2-帮助与反馈" aria-label="Permalink to &quot;6.2. 帮助与反馈&quot;">​</a></h3><ul><li>[ ] 前端反馈页面</li><li>[ ] 反馈支持选择多张图片</li><li>[ ] 帵助中心</li></ul><h3 id="_6-3-关于页" tabindex="-1">6.3. 关于页 <a class="header-anchor" href="#_6-3-关于页" aria-label="Permalink to &quot;6.3. 关于页&quot;">​</a></h3><ul><li>[ ] 展示版本号</li><li>[ ] 展示隐私政策</li><li>[ ] 权限说明</li><li>[ ] 用户协议</li></ul><hr><h2 id="阶段七-后端完善" tabindex="-1">阶段七：后端完善 <a class="header-anchor" href="#阶段七-后端完善" aria-label="Permalink to &quot;阶段七：后端完善&quot;">​</a></h2><h3 id="_7-1-基础服务" tabindex="-1">7.1. 基础服务 <a class="header-anchor" href="#_7-1-基础服务" aria-label="Permalink to &quot;7.1. 基础服务&quot;">​</a></h3><ul><li>[ ] HTTPS 实现</li><li>[ ] 阿里云数据库服务接入</li><li>[ ] 图片上传接口（区分业务来源）</li><li>[ ] 后端项目规范与包结构规范完善</li></ul><h3 id="_7-2-高级服务" tabindex="-1">7.2. 高级服务 <a class="header-anchor" href="#_7-2-高级服务" aria-label="Permalink to &quot;7.2. 高级服务&quot;">​</a></h3><ul><li>[ ] 服务平滑升级（Kubernetes 探索）</li><li>[ ] 运营配置系统（配置管理后台）</li></ul><h3 id="_7-3-后台管理系统" tabindex="-1">7.3. 后台管理系统 <a class="header-anchor" href="#_7-3-后台管理系统" aria-label="Permalink to &quot;7.3. 后台管理系统&quot;">​</a></h3><ul><li>[ ] 用户管理（查看用户列表、禁用用户）</li><li>[ ] 反馈管理（查看用户反馈）</li><li>[ ] 版本管理（推送新版本）</li><li>[ ] 公告管理（APP 内公告推送）</li><li>[ ] 运营配置（动态配置 APP 内容）</li></ul><hr><h2 id="阶段八-会员与商业化" tabindex="-1">阶段八：会员与商业化 <a class="header-anchor" href="#阶段八-会员与商业化" aria-label="Permalink to &quot;阶段八：会员与商业化&quot;">​</a></h2><h3 id="_8-1-会员体系" tabindex="-1">8.1. 会员体系 <a class="header-anchor" href="#_8-1-会员体系" aria-label="Permalink to &quot;8.1. 会员体系&quot;">​</a></h3><ul><li>[ ] 探索会员业务设计</li><li>[ ] 微信支付接入</li><li>[ ] 支付宝支付接入</li></ul><hr><h2 id="阶段九-运营与发布" tabindex="-1">阶段九：运营与发布 <a class="header-anchor" href="#阶段九-运营与发布" aria-label="Permalink to &quot;阶段九：运营与发布&quot;">​</a></h2><h3 id="_9-1-官网建设" tabindex="-1">9.1. 官网建设 <a class="header-anchor" href="#_9-1-官网建设" aria-label="Permalink to &quot;9.1. 官网建设&quot;">​</a></h3><ul><li>[ ] 官网制作与美化</li><li>[ ] 官网部署</li><li>[ ] html-report 网页 skill 安装</li></ul><h3 id="_9-2-法律合规" tabindex="-1">9.2. 法律合规 <a class="header-anchor" href="#_9-2-法律合规" aria-label="Permalink to &quot;9.2. 法律合规&quot;">​</a></h3><ul><li>[ ] 用户隐私政策</li><li>[ ] 用户数据存储风险评估</li><li>[ ] 开源项目引用公示</li><li>[ ] 支付相关法律合规</li></ul><h3 id="_9-3-应用商店上架" tabindex="-1">9.3. 应用商店上架 <a class="header-anchor" href="#_9-3-应用商店上架" aria-label="Permalink to &quot;9.3. 应用商店上架&quot;">​</a></h3><ul><li>[ ] APP 更新机制实现</li><li>[ ] iOS App Store 上架</li><li>[ ] 荣耀应用商店上架</li><li>[ ] 小米应用商店上架</li><li>[ ] OPPO 应用商店上架</li><li>[ ] vivo 应用商店上架</li><li>[ ] 华为应用商店上架</li></ul><hr><h2 id="附录-待探索项目" tabindex="-1">附录：待探索项目 <a class="header-anchor" href="#附录-待探索项目" aria-label="Permalink to &quot;附录：待探索项目&quot;">​</a></h2><p>这些是参考研究，寻找灵感和最佳实践。</p><ul><li>[ ] 哆啦宝工具箱探索</li><li>[ ] GitHub 小工具合集探索</li><li>[ ] 安装 gstack 并并探索可用技能</li></ul>',90)])])}const q=a(h,[["render",o]]);export{b as __pageData,q as default};
